import Link from 'next/link';
import results from './results.json';

// Numbers are generated by `winnow eval` (apps/api/winnow_api/eval) and
// committed as results.json. This page renders them — never hardcode
// eval numbers here, or the site and the harness drift apart.

type LaneMetrics = { precision: number; recall: number; f1: number; support: number };
type StrategyMetrics = {
  name: string;
  n: number;
  accuracy: number;
  macro_f1: number;
  per_lane: Record<string, LaneMetrics>;
  mean_latency_ms: number;
  p95_latency_ms: number;
  cost_per_1000_usd: number;
  escalation_rate: number;
};

const STRATEGY_LABEL: Record<string, string> = {
  pure_classifier: 'Pure classifier',
  pure_llm: 'Pure LLM',
  tiered: 'Tiered (Winnow)',
};
const STRATEGY_ORDER = ['pure_classifier', 'pure_llm', 'tiered'];

const pct = (x: number) => `${(x * 100).toFixed(1)}%`;
const ms = (x: number) => (x < 1000 ? `${x.toFixed(1)} ms` : `${(x / 1000).toFixed(2)} s`);
const usd = (x: number) => `$${x.toFixed(4)}`;
const thr = (x: number) => x.toFixed(4).replace(/0+$/, '').replace(/\.$/, '');

export default function EvalsPage() {
  const strategies = results.strategies as Record<string, StrategyMetrics>;
  const sweep = results.threshold_sweep as Array<{
    threshold: number;
    escalation_rate: number;
    accuracy: number;
    macro_f1: number;
    cost_per_1000_usd: number;
    mean_latency_ms: number;
  }>;
  const isStub = results.tier_2_provenance === 'stub';
  const tiered = strategies.tiered;

  return (
    <main className="min-h-screen">
      <div className="mx-auto max-w-5xl px-6 py-16">
        <Link href="/" className="text-sm text-white/50 hover:text-white/80">
          ← back
        </Link>
        <h1 className="mt-4 text-3xl font-semibold">Evaluations</h1>
        <p className="mt-3 max-w-2xl text-white/60">
          Pure-classifier vs pure-LLM vs tiered, on a held-out {results.n_test}-email slice
          ({Math.round(results.test_fraction * 100)}% of the synthetic corpus, seed {results.seed}).
          Reproducible with <code className="text-emerald-300/90">winnow eval</code>.
        </p>

        {isStub && (
          <div className="mt-6 rounded-lg border border-amber-500/30 bg-amber-500/10 p-4 text-sm text-amber-100/90">
            <strong>Tier-2 is stubbed in this run.</strong> The LLM fixtures are rule-based
            placeholders whose lanes mirror ground truth, so the <em>accuracy</em> columns for
            Pure&nbsp;LLM and Tiered are not meaningful. Latency and cost are modeled from token
            counts at Claude Opus pricing. Classifier accuracy, escalation rate, and all
            timing/cost figures are real.
          </div>
        )}

        {/* headline comparison */}
        <h2 className="mt-12 text-xl font-semibold">Strategy comparison</h2>
        <div className="mt-4 overflow-x-auto">
          <table className="w-full text-sm border-collapse">
            <thead>
              <tr className="text-left text-white/50 border-b border-white/10">
                <th className="py-2 pr-4 font-medium">Strategy</th>
                <th className="py-2 px-3 font-medium">Accuracy</th>
                <th className="py-2 px-3 font-medium">Macro-F1</th>
                <th className="py-2 px-3 font-medium">Mean latency</th>
                <th className="py-2 px-3 font-medium">p95</th>
                <th className="py-2 px-3 font-medium">Cost / 1000</th>
                <th className="py-2 px-3 font-medium">Escalated</th>
              </tr>
            </thead>
            <tbody>
              {STRATEGY_ORDER.map((name) => {
                const m = strategies[name];
                const highlight = name === 'tiered';
                return (
                  <tr
                    key={name}
                    className={`border-b border-white/5 ${highlight ? 'bg-emerald-500/5' : ''}`}
                  >
                    <td className="py-2 pr-4 font-medium">
                      {STRATEGY_LABEL[name]}
                      {highlight && <span className="ml-2 text-xs text-emerald-300/80">★</span>}
                    </td>
                    <td className="py-2 px-3 tabular-nums">{pct(m.accuracy)}</td>
                    <td className="py-2 px-3 tabular-nums">{m.macro_f1.toFixed(3)}</td>
                    <td className="py-2 px-3 tabular-nums">{ms(m.mean_latency_ms)}</td>
                    <td className="py-2 px-3 tabular-nums">{ms(m.p95_latency_ms)}</td>
                    <td className="py-2 px-3 tabular-nums">{usd(m.cost_per_1000_usd)}</td>
                    <td className="py-2 px-3 tabular-nums">{pct(m.escalation_rate)}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
        <p className="mt-3 text-sm text-white/50">
          Tiered matches the LLM&apos;s routing at classifier speed and cost — because tier-1 is
          confident on clean data and rarely escalates.
        </p>

        {/* threshold sweep */}
        <h2 className="mt-12 text-xl font-semibold">Threshold selection</h2>
        <p className="mt-2 max-w-2xl text-sm text-white/60">
          As the tier-1 confidence threshold rises, more email escalates to the LLM — trading
          cost and latency for a second opinion. On this near-separable corpus tier-1 confidences
          saturate near 1.0, so escalation only turns on above ~0.99; on a real inbox the
          threshold does meaningful work at ordinary values.
        </p>
        <div className="mt-4 overflow-x-auto">
          <table className="w-full text-sm border-collapse">
            <thead>
              <tr className="text-left text-white/50 border-b border-white/10">
                <th className="py-2 pr-4 font-medium">Threshold</th>
                <th className="py-2 px-3 font-medium">Escalated</th>
                <th className="py-2 px-3 font-medium">Accuracy</th>
                <th className="py-2 px-3 font-medium">Cost / 1000</th>
                <th className="py-2 px-3 font-medium">Mean latency</th>
              </tr>
            </thead>
            <tbody>
              {sweep.map((p) => (
                <tr key={p.threshold} className="border-b border-white/5">
                  <td className="py-2 pr-4 tabular-nums">{thr(p.threshold)}</td>
                  <td className="py-2 px-3 tabular-nums">{pct(p.escalation_rate)}</td>
                  <td className="py-2 px-3 tabular-nums">{pct(p.accuracy)}</td>
                  <td className="py-2 px-3 tabular-nums">{usd(p.cost_per_1000_usd)}</td>
                  <td className="py-2 px-3 tabular-nums">{ms(p.mean_latency_ms)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* per-lane */}
        <h2 className="mt-12 text-xl font-semibold">Per-lane breakdown (tiered)</h2>
        <div className="mt-4 overflow-x-auto">
          <table className="w-full text-sm border-collapse">
            <thead>
              <tr className="text-left text-white/50 border-b border-white/10">
                <th className="py-2 pr-4 font-medium">Lane</th>
                <th className="py-2 px-3 font-medium">Precision</th>
                <th className="py-2 px-3 font-medium">Recall</th>
                <th className="py-2 px-3 font-medium">F1</th>
                <th className="py-2 px-3 font-medium">Support</th>
              </tr>
            </thead>
            <tbody>
              {Object.entries(tiered.per_lane).map(([lane, lm]) => (
                <tr key={lane} className="border-b border-white/5">
                  <td className="py-2 pr-4">{lane}</td>
                  <td className="py-2 px-3 tabular-nums">{lm.precision.toFixed(3)}</td>
                  <td className="py-2 px-3 tabular-nums">{lm.recall.toFixed(3)}</td>
                  <td className="py-2 px-3 tabular-nums">{lm.f1.toFixed(3)}</td>
                  <td className="py-2 px-3 tabular-nums">{lm.support}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div className="mt-12 text-xs text-white/40">
          Generated {new Date(results.generated_at).toISOString().slice(0, 10)} · reproducible
          from the seeded split · full notes in{' '}
          <code className="text-white/60">docs/evals.md</code>.
        </div>
      </div>
    </main>
  );
}
